<template>
  <el-dialog :visible.sync="visible" width="360px" :show-close="true" @close="visible = false" custom-class="purchase-member-dialog">
    <!-- 非会员：购买页 -->
    <div v-if="!isMember" class="pm-wrap">
      <div class="pm-title">开通会员</div>
      <div class="tab-box">
        <a v-for="(item, index) in vipPackageList" :key="index" class="tab" :class="{ active: tabIndex === index }" @click="tabChange(item, index)">{{
          item.name
        }}</a>
      </div>
      <div class="price" v-if="vipPackageList.length">￥{{ vipPackageList[tabIndex].amount }}</div>
      <div class="canvas" v-if="payCodeUrlStatus">
        <div class="pay-mask" :style="{ backgroundImage: 'url(' + payCodeUrl + ')' }">
          <button @click="payQrCode(vipPackageList[tabIndex].id)" class="pay-button">点击购买</button>
        </div>
        <div class="tip"><em>您不是VIP会员</em></div>
      </div>
      <div class="qrcode-box" v-else>
        <el-image :src="payCodeUrl" style="width: 180px; height: 180px" />
        <div class="tip">请使用微信/支付宝扫码支付</div>
      </div>
    </div>

    <!-- 会员：信息页 -->
    <div v-else class="pm-wrap">
      <div class="pm-title">会员信息</div>
      <div class="pm-avatar">
        <i class="el-icon-user-solid pm-avatar-icon"></i>
      </div>
      <div class="pm-info-list">
        <div class="pm-info-row">
          <span class="pm-info-label">账号</span>
          <span class="pm-info-value">{{ userInfo.account }}</span>
        </div>
        <div class="pm-info-row">
          <span class="pm-info-label">会员级别</span>
          <span class="pm-info-value pm-vip-tag">{{ memberVipLevel }}</span>
        </div>
        <div class="pm-info-row">
          <span class="pm-info-label">注册时间</span>
          <span class="pm-info-value">{{ userInfo.createTime || '-' }}</span>
        </div>
        <div class="pm-info-row">
          <span class="pm-info-label">最后登录</span>
          <span class="pm-info-value">{{ userInfo.lastLoginDate || '-' }}</span>
        </div>
        <div class="pm-info-row">
          <span class="pm-info-label">会员到期</span>
          <span class="pm-info-value" :class="{ 'pm-expire-soon': isExpireSoon }">{{ userInfo.expirationDate || '-' }}</span>
        </div>
      </div>
      <el-button size="small" round style="width: 100%; margin-top: 16px; background: black; color: cyan" @click="handleRenew">续费会员</el-button>
    </div>
  </el-dialog>
</template>

<script>
import { handleAddOrder } from '@/api/importFile';
import { getMemUserInfo } from '@/api/main';

export default {
  name: 'PurchaseMember',
  props: {
    vipPackageList: { type: Array, default: () => [] },
    userInfo: { type: Object, default: () => ({}) }
  },
  data() {
    return {
      visible: false,
      tabIndex: 0,
      payCodeUrl: require('@/assets/pay-demo.png'),
      payCodeUrlStatus: true,
      intervalId: null
    };
  },
  computed: {
    isMember() {
      return !!(this.userInfo && this.userInfo.level);
    },
    memberVipLevel() {
      if (this.userInfo && this.userInfo.level) {
        const item = this.vipPackageList.find((item) => item.id === String(this.userInfo.level));
        return item ? item.name : '萌新';
      }
      return '萌新';
    },
    isExpireSoon() {
      if (!this.userInfo || !this.userInfo.expirationDate) return false;
      const expire = new Date(this.userInfo.expirationDate).getTime();
      const now = Date.now();
      return expire - now < 7 * 24 * 60 * 60 * 1000; // 7天内到期
    }
  },
  beforeDestroy() {
    this.stopInterval();
  },
  methods: {
    handleOpen() {
      this.visible = true;
      if (!this.isMember && this.vipPackageList.length) {
        this.payCodeUrlStatus = true;
        this.payCodeUrl = require('@/assets/pay-demo.png');
      }
    },
    tabChange(item, index) {
      this.tabIndex = index;
      this.stopInterval();
      this.payQrCode(item.id);
    },
    payQrCode(vipPackageId) {
      handleAddOrder({ packageLevel: vipPackageId }).then((response) => {
        this.payCodeUrl = response.data;
        this.payCodeUrlStatus = false;
        this.startInterval();
      });
    },
    startInterval() {
      this.intervalId = setInterval(async () => {
        const response = await getMemUserInfo();
        if (response.data && response.data.vipFlag) {
          this.stopInterval();
          this.$emit('refreshUserInfo');
        }
      }, 2000);
    },
    stopInterval() {
      if (this.intervalId) {
        clearInterval(this.intervalId);
        this.intervalId = null;
      }
    },
    handleRenew() {
      // 切换到购买视图（临时覆盖 isMember 显示购买页）
      this.payCodeUrlStatus = true;
      this.payCodeUrl = require('@/assets/pay-demo.png');
      if (this.vipPackageList.length) {
        this.payQrCode(this.vipPackageList[0].id);
      }
    }
  }
};
</script>

